import{_ as e}from"./chunks/k8s-grafana-template-21410-nodes-wide-annotated.DQAaQJi1.js";import{_ as s}from"./chunks/k8s-grafana-template-21410-node-resources-wide-annotated.CMQjGfrj.js";import{b as a,a as d,_ as i}from"./chunks/k8s-grafana-template-21410-namespaces-wide-annotated.uOrVVmf_.js";import{_ as o,c as n,o as r,aN as p}from"./chunks/framework.CqA5BTDU.js";const h="/kb/assets/k8s-grafana-datasource-prometheus-url-annotated.Dmr7lUnA.png",l="/kb/assets/k8s-grafana-import-dashboard-id-wide-annotated.DXVOwAds.png",c="/kb/assets/k8s-grafana-template-21410-overview-wide-annotated.KJMhpUiU.png",k="/kb/assets/k8s-grafana-template-21410-resource-count-wide-annotated.KcQlySZR.png",B=JSON.parse('{"title":"K8s监控看板","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/20-K8s监控看板.md","filePath":"12.可观测性与监控告警/20-K8s监控看板.md","lastUpdated":null}'),m={name:"12.可观测性与监控告警/20-K8s监控看板.md"};function u(b,t,g,y,F,P){return r(),n("div",null,[...t[0]||(t[0]=[p('<h1 id="k8s监控看板" tabindex="-1">K8s监控看板 <a class="header-anchor" href="#k8s监控看板" aria-label="Permalink to &quot;K8s监控看板&quot;">​</a></h1><p>K8s 看板用于把 Prometheus 里的指标按排查路径固定下来。Prometheus 负责采集和查询，Grafana 负责把常用查询组织成稳定视图。K8s 场景里常见的下钻顺序是集群、节点、namespace、workload、pod、container，再结合告警和事件判断影响范围。</p><p>当前看板基于 K3s 集群和 kube-prometheus-stack，K3s 部署参考 <a href="/kb/10.Kubernetes/05-K3s安装部署">K3s 安装部署</a>，监控栈部署参考 <a href="/kb/12.可观测性与监控告警/13-K3s部署监控栈">K3s部署监控栈</a>。</p><h2 id="一、数据源" tabindex="-1">一、数据源 <a class="header-anchor" href="#一、数据源" aria-label="Permalink to &quot;一、数据源&quot;">​</a></h2><p>Grafana 查询 Prometheus 时，不是直接访问 NodePort，而是通过集群内 Service 访问 Prometheus。这样 Grafana Pod 和 Prometheus Pod 都在集群里，访问链路更短，也不受外部端口变化影响。</p><p>当前 Grafana 入口：</p><table tabindex="0"><thead><tr><th>项目</th><th>值</th></tr></thead><tbody><tr><td>地址</td><td><code>http://192.168.10.11:30300</code></td></tr><tr><td>用户</td><td><code>admin</code></td></tr><tr><td>密码</td><td><code>admin123</code></td></tr></tbody></table><p>操作路径：</p><p><code>Connections -&gt; Data sources -&gt; Prometheus</code> （中文：连接 -&gt; 数据源 -&gt; Prometheus）</p><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写值</th><th>说明</th></tr></thead><tbody><tr><td><code>Name</code></td><td><code>Prometheus</code></td><td>后续 Dashboard 模板选择的数据源名称</td></tr><tr><td><code>Prometheus server URL</code></td><td><code>http://kps-prometheus.monitoring:9090</code></td><td>Grafana Pod 通过集群 DNS 访问 Prometheus Service</td></tr><tr><td><code>Authentication methods</code></td><td><code>No Authentication</code></td><td>当前 Prometheus 没有额外认证</td></tr></tbody></table><p>保存后验证：</p><p><code>Connections -&gt; Data sources -&gt; Prometheus -&gt; Save &amp; test</code> （中文：连接 -&gt; 数据源 -&gt; Prometheus -&gt; 保存并测试）</p><p>出现 <code>Successfully queried the Prometheus API</code>，说明 Grafana 可以查询 Prometheus。</p><p><img src="'+h+`" alt="Grafana Prometheus 数据源 URL"></p><p>命令行也可以验证数据源健康状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin:admin123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  http://127.0.0.1:30300/api/datasources/uid/prometheus/health</span></span></code></pre></div><p>返回里有 <code>Successfully queried the Prometheus API</code>，数据源链路就是通的。</p><h2 id="二、导入现成模板" tabindex="-1">二、导入现成模板 <a class="header-anchor" href="#二、导入现成模板" aria-label="Permalink to &quot;二、导入现成模板&quot;">​</a></h2><p>K8s 看板不适合从零随手拼几个面板。现成模板能覆盖一批常见维度，比如节点健康、资源请求、Pod 状态、namespace 分布和 Deployment 副本状态。导入后再根据环境修变量和查询，比直接做一张空白 Dashboard 更容易形成可用视图。</p><p>操作路径：</p><p><code>Dashboards -&gt; New -&gt; Import</code> （中文：仪表盘 -&gt; 新建 -&gt; 导入）</p><p>操作步骤：</p><ol><li>进入 <code>Dashboards -&gt; New -&gt; Import</code>。</li><li>在 <code>Find and import dashboards for common applications at grafana.com/dashboards</code> 输入模板 ID。</li><li>点击 <code>Load</code>。</li><li>在导入确认页选择数据源 <code>Prometheus</code>。</li><li>点击 <code>Import</code> 保存。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写值</th><th>说明</th></tr></thead><tbody><tr><td>Dashboard ID</td><td><code>21410</code></td><td><code>Kubernetes / Overview</code>，当前主看板</td></tr><tr><td>Datasource</td><td><code>Prometheus</code></td><td>对应上面配置的数据源</td></tr><tr><td>Folder</td><td>默认或自定义目录</td><td>小环境里默认目录即可</td></tr></tbody></table><p><img src="`+l+'" alt="Grafana 导入 Dashboard ID"></p><p>本次保留的模板：</p><table tabindex="0"><thead><tr><th>ID</th><th>名称</th><th>用途</th></tr></thead><tbody><tr><td><code>21410</code></td><td><code>Kubernetes / Overview</code></td><td>主看板，覆盖全局资源、对象数量、节点、namespace</td></tr><tr><td><code>14518</code></td><td><code>Kubernetes Cluster Overall Dashboard</code></td><td>补充节点列表和 namespace 网络流量</td></tr><tr><td><code>13332</code></td><td><code>kube-state-metrics-v2</code></td><td>补充 kube-state-metrics 对象状态，尤其是 Deployment 副本</td></tr></tbody></table><p>导入完成后，Dashboard 右上角时间范围先用 <code>Last 30 minutes</code>，刷新间隔可以设为 <code>30s</code>。刚部署完的集群历史数据少，时间范围太大时图上会有一段空白。</p><h2 id="三、全局资源视图" tabindex="-1">三、全局资源视图 <a class="header-anchor" href="#三、全局资源视图" aria-label="Permalink to &quot;三、全局资源视图&quot;">​</a></h2><p>全局视图先看 CPU、内存和对象数量。这里不是为了判断某台机器的 Linux 负载，而是先确认集群资源池是否足够、requests 和 limits 是否明显偏离实际使用。</p><p><img src="'+c+'" alt="Kubernetes Overview 全局资源"></p><p>几个指标的含义：</p><table tabindex="0"><thead><tr><th>面板</th><th>看法</th></tr></thead><tbody><tr><td><code>Real</code></td><td>当前真实使用量，来自实际采集到的资源消耗</td></tr><tr><td><code>Requests</code></td><td>Pod 声明的资源请求，调度器主要按它判断能不能放下</td></tr><tr><td><code>Limits</code></td><td>Pod 资源上限，CPU 会被限制，内存超过后可能 OOM</td></tr><tr><td><code>Workload / Total Pod / Total Nodes</code></td><td>对象规模，用来判断当前集群大概跑了多少东西</td></tr></tbody></table><p>资源请求长期接近总量时，扩容或发布新 Pod 会更容易 Pending。真实使用很低但 requests 很高，常见原因是资源声明偏保守；真实使用接近 limits，容器可能出现 CPU throttling 或 OOM。</p><p>资源对象数量和 Pod QoS 可以放在同一屏里看：</p><p><img src="'+k+'" alt="Kubernetes 资源对象数量和 Pod QoS"></p><p>QoS 这里反映 Pod 的资源声明情况：</p><table tabindex="0"><thead><tr><th>QoS</th><th>常见情况</th></tr></thead><tbody><tr><td><code>Guaranteed</code></td><td>CPU 和内存的 requests、limits 都设置且相等</td></tr><tr><td><code>Burstable</code></td><td>设置了部分 requests 或 limits</td></tr><tr><td><code>BestEffort</code></td><td>没有设置 requests 和 limits</td></tr></tbody></table><p>节点资源紧张时，<code>BestEffort</code> Pod 更容易被驱逐。业务 Pod 大量处于 <code>BestEffort</code>，通常说明资源声明没有整理好。</p><h2 id="四、节点视图" tabindex="-1">四、节点视图 <a class="header-anchor" href="#四、节点视图" aria-label="Permalink to &quot;四、节点视图&quot;">​</a></h2><p>节点视图先看 <code>Ready</code>、<code>DiskPressure</code>、<code>MemoryPressure</code>、<code>PIDPressure</code> 这类状态。它们来自 kube-state-metrics，反映 Kubernetes API 里的 Node Condition。</p><p><img src="'+e+'" alt="Kubernetes 节点健康与资源统计"></p><p>节点表格里常看这些列：</p><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td><code>status</code></td><td>节点是否 Ready</td></tr><tr><td><code>cpu req%</code></td><td>当前节点上 Pod requests 占节点 CPU 的比例</td></tr><tr><td><code>mem req%</code></td><td>当前节点上 Pod requests 占节点内存的比例</td></tr><tr><td><code>mem limit%</code></td><td>当前节点上 Pod limits 占节点内存的比例</td></tr><tr><td><code>pod</code></td><td>当前节点承载的 Pod 数量</td></tr></tbody></table><p>节点状态表里全是 <code>OK</code>，只说明 Node Condition 没有异常。实际 CPU、内存曲线还要继续看。</p><p><img src="'+s+'" alt="Kubernetes 节点 CPU 和内存曲线"></p><p>节点 CPU 有尖峰时，先看是否某个 Pod 突然消耗 CPU，再看 kubelet、containerd、日志采集和监控组件本身。节点内存接近高位时，结合 <code>kubectl top pod -A --sort-by=memory</code> 和 Dashboard 里的 namespace 维度继续下钻。</p><h2 id="五、namespace-和工作负载" tabindex="-1">五、namespace 和工作负载 <a class="header-anchor" href="#五、namespace-和工作负载" aria-label="Permalink to &quot;五、namespace 和工作负载&quot;">​</a></h2><p>namespace 视图用于判断异常集中在哪个业务空间。比如 Pod Pending、Failed、Unknown、Unschedulable 出现在某个 namespace 时，后续排查就从这个 namespace 下的 Deployment、Pod、Events 进入。</p><p><img src="'+a+`" alt="Kubernetes namespace Pod 状态"></p><p>namespace 表格的几列：</p><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td><code>Pods</code></td><td>当前 namespace 下 Pod 数量</td></tr><tr><td><code>Failed Pods</code></td><td>失败状态 Pod 数量</td></tr><tr><td><code>Unknown Pods</code></td><td>状态未知的 Pod 数量</td></tr><tr><td><code>Unscheduled Pods Last 5min</code></td><td>最近 5 分钟不可调度的 Pod 数量</td></tr></tbody></table><p><code>Unscheduled Pods Last 5min</code> 有值时，常见原因是资源不足、节点选择器不匹配、污点容忍不匹配、PVC 没有绑定。对应命令入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Pending Pod 分布</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --field-selector=status.phase=Pending</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Events 里通常会写出调度失败原因</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Deployment 副本状态适合用 kube-state-metrics 模板补充查看。它比“Pod Running 数量”更贴近发布状态，因为 Deployment 关心期望副本、更新副本、可用副本和不可用副本。</p><p><img src="`+d+`" alt="kube-state-metrics Deployment 副本状态"></p><p>Deployment 不可用副本大于 0 时，常见入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Deployment 当前状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">deployment-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看副本集和 Pod 是否创建成功</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rs,pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">app-labe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Events 里能看到镜像拉取、探针失败、调度失败等原因</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">deployment-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="六、promql-和看板对应关系" tabindex="-1">六、PromQL 和看板对应关系 <a class="header-anchor" href="#六、promql-和看板对应关系" aria-label="Permalink to &quot;六、PromQL 和看板对应关系&quot;">​</a></h2><p>看板上的每个面板最终都来自 PromQL。看板异常时，把面板里的查询拿到 Prometheus <code>Query</code> 页面执行，可以更快判断是数据源问题、模板变量问题，还是指标本身没有采到。</p><p>常用对应关系：</p><table tabindex="0"><thead><tr><th>看板问题</th><th>PromQL 入口</th></tr></thead><tbody><tr><td>节点数量</td><td><code>count(kube_node_info)</code></td></tr><tr><td>节点 Ready</td><td><code>kube_node_status_condition{condition=&quot;Ready&quot;}</code></td></tr><tr><td>Pod 数量</td><td><code>count(kube_pod_info)</code></td></tr><tr><td>namespace Pod 分布</td><td><code>count by (namespace) (kube_pod_info)</code></td></tr><tr><td>Pod 重启</td><td><code>increase(kube_pod_container_status_restarts_total[30m])</code></td></tr><tr><td>Deployment 不可用副本</td><td><code>kube_deployment_status_replicas_unavailable</code></td></tr><tr><td>CPU 使用率</td><td><code>rate(container_cpu_usage_seconds_total{container!=&quot;&quot;}[5m])</code></td></tr><tr><td>内存使用量</td><td><code>container_memory_working_set_bytes{container!=&quot;&quot;}</code></td></tr></tbody></table><p>Prometheus <code>Query</code> 适合调试看板里的 PromQL。比如 namespace 维度的 Pod 分布，可以直接查 kube-state-metrics 指标：</p><p>操作路径：</p><p><code>Query -&gt; Table</code> （中文：查询 -&gt; 表格）</p><p>查询 Pod 对象分布：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  kube_pod_info</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><img src="`+i+'" alt="Prometheus 查询 Pod 对象指标"></p><h2 id="七、排错入口" tabindex="-1">七、排错入口 <a class="header-anchor" href="#七、排错入口" aria-label="Permalink to &quot;七、排错入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>检查入口</th><th>常见原因</th></tr></thead><tbody><tr><td>Dashboard 全部无数据</td><td><code>Connections -&gt; Data sources -&gt; Prometheus -&gt; Save &amp; test</code></td><td>数据源 URL 错、Prometheus Service 不通、认证配置不一致</td></tr><tr><td>只有部分面板无数据</td><td>面板编辑页查看 PromQL 和变量</td><td>模板依赖的指标当前没有采到，或变量没有选中</td></tr><tr><td>下拉变量为空</td><td>Dashboard 顶部变量、Prometheus 查询 <code>label_values</code> 对应指标</td><td>变量查询依赖的指标不存在，或数据源 UID 映射错</td></tr><tr><td>图上只有一小段数据</td><td>右上角时间范围</td><td>刚部署完历史数据少，时间范围比采集时长大</td></tr><tr><td>namespace 或 pod 维度丢失</td><td>面板 PromQL 的 <code>sum by (...)</code></td><td>聚合时把 <code>namespace</code>、<code>pod</code>、<code>container</code> 标签聚掉了</td></tr><tr><td>面板显示数据但排查不够</td><td>回到 Prometheus <code>Query</code> 执行原始 PromQL</td><td>看板只适合固定视图，临时排查还要直接查 PromQL</td></tr></tbody></table><p>Dashboard 是排查入口，不是结论本身。真正定位时还要把看板里的异常维度带回到 <code>kubectl describe</code>、Events、Pod 日志和 Prometheus 原始查询里。</p>',73)])])}const f=o(m,[["render",u]]);export{B as __pageData,f as default};
